export function init(container, dotNetRef, timeoutMs) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("NotifyActive");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("NotifyIdle");
        }, timeoutMs);
    }

    events.forEach(evt => container.addEventListener(evt, resetTimer, { passive: true }));

    // Start the initial timer
    resetTimer();

    state = { container, events, resetTimer, timerId: () => timerId, clearTimer: () => clearTimeout(timerId) };
}

export function dispose() {
    if (!state) return;

    state.clearTimer();
    state.events.forEach(evt =>
        state.container.removeEventListener(evt, state.resetTimer)
    );
    state = null;
}

